let source = {};
try { source = $('Build Native Heartbeat').first().json || {}; } catch (e) { source = {}; }
const telegram = $input.first().json || {};
function esc(v) {
  if (v === undefined || v === null) return 'NULL';
  return "'" + String(v).replace(/'/g, "''").slice(0, 20000) + "'";
}
function ts(v) {
  const dt = new Date(v || Date.now());
  return Number.isFinite(dt.getTime()) ? esc(dt.toISOString()) : 'now()';
}
const now = new Date().toISOString();
const routeId = source.route_id || ('native_telegram_heartbeat_' + now.replace(/[-:.TZ]/g, '').slice(0, 14));
